compliant_code:
func process(items []Item) {
    for _, item := range items {
        if !item.Valid || !item.Ready {
            continue
        }
        processItem(item)
    }
}

func processItem(item Item) {
    for _, sub := range item.Parts {
        if sub.Active {
            handle(sub)
        }
    }
}
